<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8" />
<meta name="viewport" content="width=device-width, initial-scale=1.0" />
<title>Conway's Game of Life</title>
<style>
  :root {
    color-scheme: dark;
    --bg: #0b1020;
    --panel: #151d36;
    --panel-hi: #202b4d;
    --line: #2c3b65;
    --alive: #7cf7bb;
    --alive-glow: rgba(124, 247, 187, .55);
    --text: #eaf1ff;
    --muted: #9aa9cb;
    --accent: #8d7dff;
  }

  * { box-sizing: border-box; }

  body {
    margin: 0;
    min-height: 100vh;
    display: grid;
    place-items: center;
    background:
      radial-gradient(circle at 20% 15%, #1f2854 0, transparent 35%),
      radial-gradient(circle at 80% 85%, #183d4a 0, transparent 32%),
      var(--bg);
    color: var(--text);
    font-family: ui-rounded, "Trebuchet MS", system-ui, sans-serif;
  }

  .app {
    width: min(92vw, 680px);
    padding: 22px;
    text-align: center;
  }

  h1 {
    margin: 0 0 5px;
    font-size: clamp(1.7rem, 4vw, 2.5rem);
    letter-spacing: .03em;
  }

  .subtitle {
    margin: 0 0 18px;
    color: var(--muted);
    font-size: .95rem;
  }

  .board-wrap {
    position: relative;
    display: inline-block;
    padding: 10px;
    border-radius: 22px;
    background: linear-gradient(145deg, #273461, #11182d);
    box-shadow:
      0 18px 48px rgba(0, 0, 0, .42),
      inset 0 1px 1px rgba(255,255,255,.13);
  }

  #life {
    display: block;
    width: min(82vw, 560px);
    height: min(82vw, 560px);
    min-width: 400px;
    min-height: 400px;
    max-width: 100%;
    max-height: 72vh;
    aspect-ratio: 1;
    border-radius: 14px;
    background: #080d19;
    cursor: crosshair;
    touch-action: none;
  }

  .controls {
    display: flex;
    justify-content: center;
    flex-wrap: wrap;
    gap: 10px;
    margin-top: 18px;
  }

  button {
    border: 0;
    border-radius: 999px;
    padding: 11px 17px;
    color: var(--text);
    background: var(--panel);
    box-shadow: 0 5px 0 #090d1b, inset 0 1px 0 rgba(255,255,255,.12);
    font: inherit;
    font-weight: 700;
    cursor: pointer;
    transition: transform .12s ease, background .12s ease, box-shadow .12s ease;
  }

  button:hover {
    background: var(--panel-hi);
    transform: translateY(-2px);
  }

  button:active {
    transform: translateY(3px);
    box-shadow: 0 2px 0 #090d1b;
  }

  #play.playing {
    background: var(--accent);
    color: #fff;
  }

  .hint {
    margin: 15px 0 0;
    color: var(--muted);
    font-size: .85rem;
  }

  @media (max-width: 460px) {
    .app { padding: 14px 6px; }
    #life {
      min-width: 400px;
      min-height: 400px;
      transform: scale(calc((100vw - 32px) / 400));
      transform-origin: top left;
    }
    .board-wrap {
      width: calc(100vw - 20px);
      height: calc(100vw - 20px);
      overflow: hidden;
    }
  }
</style>
</head>
<body>
  <main class="app">
    <h1>✨ Game of Life ✨</h1>
    <p class="subtitle">Click or drag to paint little living pixels.</p>

    <div class="board-wrap">
      <canvas id="life" width="560" height="560" aria-label="Conway's Game of Life grid"></canvas>
    </div>

    <div class="controls">
      <button id="step" type="button">⏭ Step</button>
      <button id="play" type="button">▶ Play</button>
      <button id="random" type="button">🎲 Random</button>
      <button id="clear" type="button">🧹 Clear</button>
    </div>

    <p class="hint">B3/S23 · edges are quiet, empty space</p>
  </main>

<script>
(() => {
  const canvas = document.getElementById("life");
  const ctx = canvas.getContext("2d");

  const w = 56;
  const h = 56;
  let cells = new Uint8Array(w * h);
  let running = false;
  let timer = null;
  let drawing = false;
  let paintValue = 1;
  let lastCell = -1;

  function index(x, y) {
    return y * w + x;
  }

  function get(x, y) {
    if (x < 0 || y < 0 || x >= w || y >= h) return 0;
    return cells[index(x, y)];
  }

  function set(x, y, value) {
    if (x < 0 || y < 0 || x >= w || y >= h) return;
    cells[index(x, y)] = value ? 1 : 0;
  }

  function draw() {
    const cw = canvas.width / w;
    const ch = canvas.height / h;

    ctx.fillStyle = "#080d19";
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    ctx.strokeStyle = "rgba(62, 80, 128, .34)";
    ctx.lineWidth = 1;
    ctx.beginPath();
    for (let x = 0; x <= w; x++) {
      const px = x * cw + 0.5;
      ctx.moveTo(px, 0);
      ctx.lineTo(px, canvas.height);
    }
    for (let y = 0; y <= h; y++) {
      const py = y * ch + 0.5;
      ctx.moveTo(0, py);
      ctx.lineTo(canvas.width, py);
    }
    ctx.stroke();

    ctx.shadowColor = "rgba(124, 247, 187, .65)";
    ctx.shadowBlur = 8;
    ctx.fillStyle = "#7cf7bb";

    for (let y = 0; y < h; y++) {
      for (let x = 0; x < w; x++) {
        if (!cells[index(x, y)]) continue;
        const pad = Math.max(1, cw * 0.12);
        ctx.fillRect(x * cw + pad, y * ch + pad, cw - pad * 2, ch - pad * 2);
      }
    }
    ctx.shadowBlur = 0;
  }

  function step() {
    const next = new Uint8Array(w * h);

    for (let y = 0; y < h; y++) {
      for (let x = 0; x < w; x++) {
        let neighbors = 0;

        for (let dy = -1; dy <= 1; dy++) {
          for (let dx = -1; dx <= 1; dx++) {
            if (dx === 0 && dy === 0) continue;
            neighbors += get(x + dx, y + dy);
          }
        }

        const alive = get(x, y);
        next[index(x, y)] = alive
          ? ((neighbors === 2 || neighbors === 3) ? 1 : 0)
          : (neighbors === 3 ? 1 : 0);
      }
    }

    cells = next;
    draw();
  }

  function clear() {
    cells.fill(0);
    draw();
  }

  function randomize() {
    for (let i = 0; i < cells.length; i++) {
      cells[i] = Math.random() < 0.28 ? 1 : 0;
    }
    draw();
  }

  function togglePlay() {
    running = !running;
    const play = document.getElementById("play");
    play.classList.toggle("playing", running);
    play.textContent = running ? "⏸ Pause" : "▶ Play";

    if (running) {
      timer = setInterval(step, 105);
    } else {
      clearInterval(timer);
      timer = null;
    }
  }

  function canvasCell(event) {
    const rect = canvas.getBoundingClientRect();
    const x = Math.floor((event.clientX - rect.left) * w / rect.width);
    const y = Math.floor((event.clientY - rect.top) * h / rect.height);
    return { x, y };
  }

  function paint(event) {
    const { x, y } = canvasCell(event);
    if (x < 0 || y < 0 || x >= w || y >= h) return;
    const i = index(x, y);
    if (i === lastCell) return;
    lastCell = i;
    set(x, y, paintValue);
    draw();
  }

  canvas.addEventListener("pointerdown", (event) => {
    drawing = true;
    lastCell = -1;
    const { x, y } = canvasCell(event);
    paintValue = get(x, y) ? 0 : 1;
    canvas.setPointerCapture(event.pointerId);
    paint(event);
  });

  canvas.addEventListener("pointermove", (event) => {
    if (drawing) paint(event);
  });

  canvas.addEventListener("pointerup", () => {
    drawing = false;
    lastCell = -1;
  });

  canvas.addEventListener("pointercancel", () => {
    drawing = false;
    lastCell = -1;
  });

  document.getElementById("step").addEventListener("click", step);
  document.getElementById("play").addEventListener("click", togglePlay);
  document.getElementById("random").addEventListener("click", randomize);
  document.getElementById("clear").addEventListener("click", clear);

  window.life = {
    w,
    h,
    get,
    set(x, y, value) {
      set(x, y, value);
      draw();
    },
    step,
    clear
  };

  randomize();
})();
</script>
</body>
</html>
